const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

const handleResponse = async (res) => {
  if (!res.ok) {
    const err = await res.json().catch(() => ({ detail: res.statusText }));
    throw new Error(err.detail || 'Erreur serveur');
  }
  return res.json();
};

// ── Health
export const ping = () =>
  fetch(`${BASE_URL}/`).then(handleResponse);

// ── TRAIN (✅ FIX ICI)
export const trainModel = (payload) =>
  fetch(`${BASE_URL}/train`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model_type: payload.model,
      hyperparameters: payload.hyperparams || {}
    }),
  }).then(handleResponse);

// ── PREDICT
export const predict = (payload) =>
  fetch(`${BASE_URL}/predict`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  }).then(handleResponse);

// ── UPLOAD
export const uploadDataset = (formData) =>
  fetch(`${BASE_URL}/upload`, {
    method: 'POST',
    body: formData,
  }).then(handleResponse);

// ── DOWNLOAD (✅ FIX URL)
export const downloadModel = async (modelId) => {
  const res = await fetch(`${BASE_URL}/download/${modelId}`);

  if (!res.ok) throw new Error('Download failed');

  const data = await res.json();
  console.log("Model path:", data.path);

  return data;
};
